import React from 'react';

const Hero = () => (
    <section style={{ padding: '100px 80px', textAlign: 'center', background: '#080402', color: '#fef3c7' }}>
        <div style={{ maxWidth: '800px', margin: '0 auto' }}>
            <span style={{ color: '#ea580c', fontWeight: '800', textTransform: 'uppercase', fontSize: '12px', letterSpacing: '2px' }}>Portal Loker No. 1 di Solo</span>
            <h1 style={{ fontSize: '3.5rem', margin: '20px 0', lineHeight: '1.1', fontWeight: '900' }}>Mastering Your <br/> <span style={{ color: '#ea580c' }}>Career Needs.</span></h1>
            <p style={{ color: '#a3a3a3', fontSize: '16px', marginBottom: '40px', lineHeight: '1.6' }}>Temukan lowongan kerja terbaik yang sesuai dengan skill dan passion Anda di wilayah Solo dan sekitarnya.</p>
            <button style={{ padding: '14px 40px', background: '#ea580c', border: 'none', borderRadius: '12px', color: '#fff', fontWeight: '800', cursor: 'pointer' }}>Mulai Eksplorasi</button>
        </div>
    </section>
);
export default Hero;
